import 'package:audioplayers/audioplayers.dart';
import 'package:path_provider/path_provider.dart';

enum _RecordState { idle, recording, recorded, playing }

class VoiceNoteRecorder extends StatefulWidget {
  final String username;
  const VoiceNoteRecorder({super.key, required this.username});

  @override
  State<VoiceNoteRecorder> createState() => _VoiceNoteRecorderState();
}

class _VoiceNoteRecorderState extends State<VoiceNoteRecorder>
    with SingleTickerProviderStateMixin {
  final _recorder = AudioRecorder();
  final _player = AudioPlayer();
  late AnimationController _waveController;
  late StreamSubscription<void> _playerSub;

  _RecordState _state = _RecordState.idle;
  String? _filePath;
  Timer? _timer;
  int _secondsElapsed = 0;
  static const _maxSeconds = 15;

  @override
  void initState() {
    super.initState();
    _waveController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1200),
    );
    _playerSub = _player.onPlayerComplete.listen((_) {
      if (mounted) setState(() => _state = _RecordState.recorded);
    });
  }

  @override
  void dispose() {
    _timer?.cancel();
    _waveController.dispose();
    _playerSub.cancel();
    _recorder.dispose();
    _player.dispose();
    super.dispose();
  }

  Future<void> _startRecording() async {
    if (!await _recorder.hasPermission()) return;

    final dir = await getTemporaryDirectory();
    _filePath =
        '${dir.path}/voice_note_${DateTime.now().millisecondsSinceEpoch}.m4a';

    await _recorder.start(
      const RecordConfig(
        encoder: AudioEncoder.aacLc,
        bitRate: 32000,
        numChannels: 1,
      ),
      path: _filePath!,
    );

    setState(() {
      _state = _RecordState.recording;
      _secondsElapsed = 0;
    });
    _waveController.repeat();

    _timer = Timer.periodic(const Duration(seconds: 1), (t) {
      if (!mounted) {
        t.cancel();
        return;
      }
      setState(() => _secondsElapsed++);
      if (_secondsElapsed >= _maxSeconds) _stopRecording();
    });
  }

  Future<void> _stopRecording() async {
    _timer?.cancel();
    _waveController.stop();
    await _recorder.stop();
    setState(() => _state = _RecordState.recorded);
  }

  Future<void> _playRecording() async {
    if (_filePath == null) return;
    setState(() => _state = _RecordState.playing);
    await _player.play(DeviceFileSource(_filePath!));
  }

  Future<void> _stopPlaying() async {
    await _player.stop();
    setState(() => _state = _RecordState.recorded);
  }

  void _reRecord() {
    setState(() {
      _state = _RecordState.idle;
      _filePath = null;
      _secondsElapsed = 0;
    });
  }

  @override
  Widget build(BuildContext context) {
    final bottom = MediaQuery.of(context).viewInsets.bottom;
    return Container(
      decoration: const BoxDecoration(
        color: Color(0xFF0E0E0E),
        borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
      ),
      padding: EdgeInsets.fromLTRB(24, 16, 24, bottom + 36),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          Container(
            width: 40,
            height: 4,
            margin: const EdgeInsets.only(bottom: 24),
            decoration: BoxDecoration(
              color: Colors.grey.shade700,
              borderRadius: BorderRadius.circular(2),
            ),
          ),
          Text(
            'WHY DO YOU LIKE ${widget.username.toUpperCase()}?',
            style: const TextStyle(
              color: Colors.white,
              fontSize: 16,
              fontWeight: FontWeight.bold,
              letterSpacing: 0.5,
            ),
            textAlign: TextAlign.center,
          ),
          const SizedBox(height: 36),
          SizedBox(height: 60, child: _buildMiddleSection()),
          const SizedBox(height: 36),
          _buildMainButton(),
          const SizedBox(height: 20),
          _buildSecondaryRow(),
          const SizedBox(height: 4),
        ],
      ),
    );
  }

  Widget _buildMiddleSection() {
    if (_state == _RecordState.recording) return _buildWaveform();
    if (_state == _RecordState.recorded || _state == _RecordState.playing) {
      return Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          const Icon(Icons.check_circle_outline,
              color: Color(0xFF4CAF50), size: 36),
          const SizedBox(height: 6),
          Text(
            '$_secondsElapsed sec recorded',
            style: const TextStyle(color: Colors.grey, fontSize: 13),
          ),
        ],
      );
    }
    return const Column(
      mainAxisAlignment: MainAxisAlignment.center,
      children: [
        Icon(Icons.mic_none, color: Colors.grey, size: 32),
        SizedBox(height: 6),
        Text(
          'Tap to record a voice note',
          style: TextStyle(color: Colors.grey, fontSize: 13),
        ),
      ],
    );
  }

  Widget _buildWaveform() {
    return AnimatedBuilder(
      animation: _waveController,
      builder: (_, __) {
        return Row(
          mainAxisAlignment: MainAxisAlignment.center,
          crossAxisAlignment: CrossAxisAlignment.center,
          children: List.generate(20, (i) {
            final phase = _waveController.value * 2 * pi;
            final height = 8.0 + 28.0 * (0.5 + 0.5 * sin(phase + i * 0.55));
            return Container(
              width: 4,
              height: height,
              margin: const EdgeInsets.symmetric(horizontal: 2),
              decoration: BoxDecoration(
                color: Colors.red,
                borderRadius: BorderRadius.circular(2),
              ),
            );
          }),
        );
      },
    );
  }

  Widget _buildMainButton() {
    switch (_state) {
      case _RecordState.idle:
        return _CircleButton(
          color: Colors.red,
          icon: Icons.mic,
          onTap: _startRecording,
        );
      case _RecordState.recording:
        return Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text(
              '${_maxSeconds - _secondsElapsed}s remaining',
              style: const TextStyle(color: Colors.grey, fontSize: 12),
            ),
            const SizedBox(height: 8),
            _CircleButton(
              color: const Color(0xFFB71C1C),
              icon: Icons.stop,
              onTap: _stopRecording,
            ),
          ],
        );
      case _RecordState.playing:
        return _CircleButton(
          color: Colors.orange,
          icon: Icons.stop,
          onTap: _stopPlaying,
        );
      case _RecordState.recorded:
        return _CircleButton(
          color: const Color(0xFF388E3C),
          icon: Icons.play_arrow,
          onTap: _playRecording,
        );
    }
  }

  Widget _buildSecondaryRow() {
    if (_state != _RecordState.recorded && _state != _RecordState.playing) {
      return const SizedBox(height: 50);
    }
    return Row(
      children: [
        Expanded(
          child: OutlinedButton.icon(
            icon: const Icon(Icons.refresh, color: Colors.grey, size: 18),
            label: const Text(
              'Re-record',
              style: TextStyle(color: Colors.grey),
            ),
            style: OutlinedButton.styleFrom(
              side: const BorderSide(color: Colors.grey),
              shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(12)),
              padding: const EdgeInsets.symmetric(vertical: 14),
            ),
            onPressed: _reRecord,
          ),
        ),
        const SizedBox(width: 12),
        Expanded(
          child: ElevatedButton.icon(
            icon: const Icon(Icons.favorite, color: Colors.white, size: 18),
            label: const Text(
              'Send Like',
              style:
                  TextStyle(color: Colors.white, fontWeight: FontWeight.bold),
            ),
            style: ElevatedButton.styleFrom(
              backgroundColor: Colors.red,
              shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(12)),
              padding: const EdgeInsets.symmetric(vertical: 14),
            ),
            onPressed: () => Navigator.of(context).pop(_filePath),
          ),
        ),
      ],
    );
  }
}

class _CircleButton extends StatelessWidget {
  final Color color;
  final IconData icon;
  final VoidCallback onTap;

  const _CircleButton({
    required this.color,
    required this.icon,
    required this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: onTap,
      child: Container(
        width: 80,
        height: 80,
        decoration: BoxDecoration(shape: BoxShape.circle, color: color),
        child: Icon(icon, color: Colors.white, size: 36),
      ),
    );
  }
}

